// n8n 2.x — réponse = sortie de ce node (responseMode: lastNode)
const raw = $input.first().json;
const body = raw.body && typeof raw.body === 'object' ? raw.body : raw;

const query = String(body.query ?? '').trim();
const assetType = body.asset_type === 'patent' ? 'patent' : 'trademark';

const catalog = assetType === 'patent'
  ? [
      { title: 'Gourde Filtrante Pro', ref: 'MA-B-2021-000892', summary: 'Brevet filtration', score: 0.71 },
      { title: 'Smart Filter Cap', ref: 'MA-B-2023-001104', summary: 'Brevet bouchon', score: 0.65 }
    ]
  : [
      { title: 'Coca Cola', ref: 'MA-M-2019-004521', summary: 'Marque classe 32', score: 0.95 },
      { title: 'Coca-Kola', ref: 'MA-M-2024-011203', summary: 'Marque similar', score: 0.88, opposition_eligible: true },
      { title: 'Koka Cola', ref: 'MA-M-2023-008877', summary: 'Marque similar', score: 0.76, opposition_eligible: true }
    ];

const q = query.toLowerCase();
const results = catalog.filter((item) => {
  if (!q) return false;
  const t = item.title.toLowerCase();
  return t.includes(q) || q.includes('coca') && t.includes('cola') || q.includes('gourde') && t.includes('gourde');
});

return [{ json: { results } }];
